#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=10000005;
ll n,ans,num,a[N],cnt;
struct node
{
	int son[2];
} b[N];
void add(ll x)
{
	num=0;
	for(int i=31;i>=0;i--)
	{
		bool flag=(1<<i)&x;
		if(!b[num].son[flag]) b[num].son[flag]=++cnt;
		num=b[num].son[flag];
	}
}
ll fun(ll x)
{
//	cout<<x<<" : ";
	ans=num=0;
	for(int i=31;i>-1;i--)
	{
		bool flag=(1<<i)&x;
		if(b[num].son[!flag])
		{
//			cout<<i<<" ";
			num=b[num].son[!flag];
			ans^=(1<<i);
		}
		else
		{
			num=b[num].son[flag];
		}
	}
//	cout<<"\n";
	return ans;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		add(a[i]);
	}
	ll mx=0;
	for(int i=1;i<=n;i++)
	{
		mx=max(mx,fun(a[i]));
	}
	cout<<mx;
	return 0;
}
